             ⚠️ Missed Opportunities
           </h3>
           <ul>
             ${data.coachingCard.missedOpportunities.length > 0 
                ? data.coachingCard.missedOpportunities.map(m => `<li>${m}</li>`).join('')
                : '<li style="color:#94a3b8; font-style:italic;">No missed opportunities detected.</li>'
             }
