        </tbody>
      </table>
    `;
    triggerBrowserPrint(`QA Batch Report ${dateStr}`, html);
    return;
  }

  // CSV Generation (Unchanged)
  const summaryHeaders = ['Metric', 'Value'];
  const summaryRows = [
    ['Total Calls', stats.totalCalls],
