import { AppState, SalesAnalysisResult, SavedCall, DealInteraction, FullDealAnalysis } from './types';
import { Activity, RefreshCcw, Sparkles, MessageSquare, Menu, Save, Check, Layout, BrainCircuit, ListTodo, FileText, ShieldCheck, Download, ChevronDown, FileSpreadsheet } from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { QAModule } from './components/QAModule';
import { CallLibrary } from './components/library/CallLibrary';
import { TrendsDashboard } from './components/trends/TrendsDashboard';
import { LiveCopilot } from './components/live/LiveCopilot';
import { DealUpload } from './components/deal/DealUpload';
import { DealDashboard } from './components/deal/DealDashboard';
import { saveCall } from './services/storageService';
import { exportSingleCallReport } from './services/exportService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'COACH' | 'QA' | 'LIBRARY' | 'TRENDS' | 'LIVE' | 'DEAL'>('COACH');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // COACHING STATE
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<SalesAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [currentAudioTime, setCurrentAudioTime] = useState<number | null>(null);
  const [transcriptSearchTerm, setTranscriptSearchTerm] = useState('');
  const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [fileName, setFileName] = useState('');
  const [showExportMenu, setShowExportMenu] = useState(false);

  // DEAL STATE
  const [dealAnalysis, setDealAnalysis] = useState<FullDealAnalysis | null>(null);
  const [isDealAnalyzing, setIsDealAnalyzing] = useState(false);

  // TAB STATE
  const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'INTEL' | 'COACHING' | 'COMPLIANCE' | 'TRANSCRIPT'>('OVERVIEW');

  const handleFileSelect = async (file: File) => {
    setAppState(AppState.ANALYZING);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(0);
    setFileName(file.name);
    setIsSaved(false);

    if (audioUrl) URL.revokeObjectURL(audioUrl);
    const url = URL.createObjectURL(file);
    setAudioUrl(url);

    try {
      const data = await analyzeSalesCall(file);
      setResult(data);
      setAppState(AppState.COMPLETE);
      setActiveTab('OVERVIEW'); // Reset to overview on new file
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze the audio file.");
      setAppState(AppState.ERROR);
    }
  };

  const handleDealAnalyze = async (interactions: DealInteraction[]) => {
    setIsDealAnalyzing(true);
    try {
      const result = await analyzeFullDeal(interactions);
      setDealAnalysis(result);
    } catch (e: any) {
      alert("Failed to analyze deal: " + e.message);
    } finally {
      setIsDealAnalyzing(false);
    }
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(null);
    setIsSaved(false);
    setShowExportMenu(false);
    if (audioUrl) {
      URL.revokeObjectURL(audioUrl);
      setAudioUrl(null);
    }
  };

  const handleSaveToLibrary = async () => {
    if (result && !isSaved) {
      try {
        await saveCall(result, fileName);
        setIsSaved(true);
      } catch (e) {
        console.error("Failed to save", e);
        alert("Failed to save to local library.");
      }
    }
  };

  const handleExportReport = (format: 'CSV' | 'PDF') => {
    if (result) {
      exportSingleCallReport(result, fileName, format);
      setShowExportMenu(false);
    }
  };

  const loadFromLibrary = (call: SavedCall) => {
    setResult(call.analysisData);
    setAppState(AppState.COMPLETE);
    setFileName(call.fileName);
    setIsSaved(true);
    setAudioUrl(null); // Audio blob is not stored in this version
    setCurrentView('COACH');
    setActiveTab('OVERVIEW');
  };

  const handleTopicClick = (topicName: string) => {
    setTranscriptSearchTerm(topicName);
    setActiveTab('TRANSCRIPT'); // Switch to transcript view
  };

  const handleTimestampClick = (time: number) => {
    setCurrentAudioTime(time);
  };

  // Render content based on active tab within COACH view
  const renderCoachTabs = () => {
    if (!result) return null;

    switch (activeTab) {
      case 'OVERVIEW':
        return (
          <div className="animate-fade-in space-y-8">
             <StatsOverview 
                stats={result.callStats} 
                ratio={result.talkRatio} 
                silence={result.silenceAnalysis}
              />
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                 {/* Explicit Height for Charts */}
                 <div className="h-[450px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
                    <SentimentChart 
                      data={result.sentimentGraph} 
                      highlightedTime={currentAudioTime} 
                    />
                 </div>
                 <div className="h-[450px]">
                    <TopicsChart topics={result.topics} competitors={result.competitors} onTopicClick={handleTopicClick} />
                 </div>
              </div>
              <CustomerProfile profile={result.customerProfile} followUp={result.followUp} />
          </div>
        );
      case 'INTEL':
        return (
          <div className="animate-fade-in space-y-8">
            <DealIntelligence 
              risk={result.dealIntelligence.riskAnalysis}
              committee={result.dealIntelligence.buyingCommittee}
              stage={result.dealIntelligence.dealStage}
              intents={result.dealIntelligence.intents}
            />
          </div>
        );
      case 'COMPLIANCE':
        return (
          <div className="animate-fade-in">
             <CompliancePanel compliance={result.compliance} />
          </div>
        );
      case 'COACHING':
        return (
          <div className="animate-fade-in">
             <CoachingCard coaching={result.coachingCard} />
          </div>
        );
      case 'TRANSCRIPT':
        return (
          <div className="animate-fade-in h-[calc(100vh-200px)]">
             <TranscriptView 
                transcript={result.transcript || []} 
                searchTerm={transcriptSearchTerm}
                onSearchChange={setTranscriptSearchTerm}
                onTimestampClick={handleTimestampClick}
                currentAudioTime={currentAudioTime}
              />
          </div>
        );
      default: return null;
    }
  };

  const renderContent = () => {
    switch(currentView) {
      case 'QA': return <QAModule />;
      case 'LIBRARY': return <CallLibrary onLoadCall={loadFromLibrary} />;
      case 'TRENDS': return <TrendsDashboard />;
      case 'LIVE': return <LiveCopilot />;
      case 'DEAL': return !dealAnalysis ? (
        <DealUpload onAnalyze={handleDealAnalyze} isAnalyzing={isDealAnalyzing} />
      ) : (
        <div className="animate-fade-in">
           <button onClick={() => setDealAnalysis(null)} className="mb-4 text-sm text-slate-500 hover:text-blue-600 flex items-center gap-1">
             <RefreshCcw className="w-4 h-4" /> Start New Analysis
           </button>
           <DealDashboard analysis={dealAnalysis} />
        </div>
      );
      default: return (
        <div className="max-w-7xl mx-auto space-y-6 pb-32">
             {/* Header for Single Call Mode */}
             <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4 mb-4">
                <div>
                   <h1 className="text-2xl font-bold text-slate-800">Sales Call Coach</h1>
                   <p className="text-slate-500">Single call analysis & deep intelligence.</p>
                </div>
                {appState === AppState.COMPLETE && result && (
                  <div className="flex items-center gap-2 self-start xl:self-auto flex-wrap">
                     <CRMIntegration data={result} />

                     {/* Export Dropdown */}
                     <div className="relative">
                        <button 
                          onClick={() => setShowExportMenu(!showExportMenu)}
                          className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold bg-white border border-slate-200"
                        >
                           <Download className="w-5 h-5" />
                           <span className="hidden sm:inline">Export Report</span>
                           <ChevronDown className="w-4 h-4" />
                        </button>
                        {showExportMenu && (
                          <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-slate-200 rounded-xl shadow-xl z-50 overflow-hidden animate-fade-in">
                            <button 
                              onClick={() => handleExportReport('PDF')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2 border-b border-slate-50"
                            >
                              <FileText className="w-4 h-4 text-red-600" /> PDF Report
                            </button>
                            <button 
                              onClick={() => handleExportReport('CSV')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                            >
                              <FileSpreadsheet className="w-4 h-4 text-green-600" /> Excel / CSV
                            </button>
                          </div>
                        )}
                     </div>

                     <button 
                       onClick={handleSaveToLibrary}
                       disabled={isSaved}
                       className={`p-2 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold ${isSaved ? 'text-emerald-600 bg-emerald-50 cursor-default' : 'text-slate-500 hover:text-blue-600 hover:bg-slate-100'}`}
                     >
                       {isSaved ? <Check className="w-5 h-5" /> : <Save className="w-5 h-5" />}
                       <span className="hidden sm:inline">{isSaved ? 'Saved to Vault' : 'Save to Library'}</span>
                     </button>
                     <button 
                        onClick={() => setIsFeedbackOpen(true)}
                        className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                      >
                        <MessageSquare className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={resetApp}
                        className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-blue-600 transition-colors bg-white border border-slate-200 px-3 py-2 rounded-lg"
                      >
                        <RefreshCcw className="w-4 h-4" />
                        <span className="hidden sm:inline">New Analysis</span>
                      </button>
                  </div>
                )}
             </div>

             {/* Tab Navigation */}
             {appState === AppState.COMPLETE && (
               <div className="flex border-b border-slate-200 mb-6 overflow-x-auto no-scrollbar">
                 <button 
                   onClick={() => setActiveTab('OVERVIEW')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'OVERVIEW' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <Layout className="w-4 h-4" /> Overview
                 </button>
                 <button 
                   onClick={() => setActiveTab('INTEL')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'INTEL' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <BrainCircuit className="w-4 h-4" /> Deal Intel
                 </button>
                 <button 
                   onClick={() => setActiveTab('COMPLIANCE')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COMPLIANCE' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ShieldCheck className="w-4 h-4" /> QA & Compliance
                 </button>
                 <button 
                   onClick={() => setActiveTab('COACHING')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COACHING' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ListTodo className="w-4 h-4" /> Coaching
                 </button>
                 <button 
                   onClick={() => setActiveTab('TRANSCRIPT')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'TRANSCRIPT' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <FileText className="w-4 h-4" /> Transcript
                 </button>
               </div>
             )}

             {/* Content */}
             {appState === AppState.IDLE || appState === AppState.ANALYZING || appState === AppState.ERROR ? (
                <div className="flex flex-col items-center justify-center min-h-[60vh]">
                   <div className="text-center mb-10 animate-fade-in-up px-4">
                     <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-bold mb-4 border border-blue-100">
                       <Sparkles className="w-3 h-3" />
                       <span>POWERED BY GEMINI 3.0 PRO</span>
                     </div>
                     <h2 className="text-4xl sm:text-5xl font-extrabold text-slate-900 mb-6 tracking-tight leading-tight">
                       Turn Sales Calls into <br/>
                       <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Revenue Science</span>
                     </h2>
                     <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                       Upload your sales recordings. Our AI engine extracts diarized transcripts, 
                       deal risks, buying committee maps, compliance scores, and follow-up emails in seconds.
                     </p>
                   </div>
                   <FileUpload onFileSelect={handleFileSelect} isAnalyzing={appState === AppState.ANALYZING} />

                   {appState === AppState.ERROR && (
                     <div className="mt-8 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 max-w-lg text-center shadow-sm mx-auto">
                       <p className="font-bold flex items-center justify-center gap-2">
                         Analysis Failed
                       </p>
                       <p className="text-sm mt-1">{error}</p>
                       <button onClick={resetApp} className="mt-3 text-xs font-bold uppercase tracking-wide text-red-800 hover:underline">Try Again</button>
                     </div>
                   )}
                </div>
              ) : null}

              {appState === AppState.COMPLETE && result && renderCoachTabs()}
          </div>
      );
    }
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans flex">
      {/* Sidebar Navigation */}
      <Sidebar 
        currentView={currentView} 
        onNavigate={setCurrentView} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 lg:ml-64 p-4 lg:p-8 transition-all duration-300 w-full overflow-hidden">

        {/* Mobile Header */}
        <div className="lg:hidden flex items-center justify-between mb-6">
           <div className="flex items-center gap-3">
             <button 
               onClick={() => setIsMobileMenuOpen(true)}
               className="p-2 text-slate-600 hover:bg-slate-200 rounded-lg"
             >
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-slate-800 text-lg">SalesIQ</span>
           </div>
        </div>

        {renderContent()}

        {/* Audio Player Bar (Only visible in COACH mode with audio) */}
        {currentView === 'COACH' && appState === AppState.COMPLETE && audioUrl && (
          <div className="lg:pl-64"> 
             <AudioPlayerBar 
               audioSrc={audioUrl} 
               onTimeUpdate={setCurrentAudioTime}
               externalCurrentTime={currentAudioTime}
             />
          </div>
        )}

        {/* Feedback Modal */}
        <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} />
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Mic, ShieldCheck, Settings, LayoutDashboard, X, Library, TrendingUp, Radio, Briefcase } from 'lucide-react';

interface SidebarProps {
  currentView: 'COACH' | 'QA' | 'LIBRARY' | 'TRENDS' | 'LIVE' | 'DEAL';
  onNavigate: (view: 'COACH' | 'QA' | 'LIBRARY' | 'TRENDS' | 'LIVE' | 'DEAL') => void;
  isOpen: boolean;
  onClose: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ currentView, onNavigate, isOpen, onClose }) => {
  return (
    <>
      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/50 z-40 lg:hidden"
          onClick={onClose}
        />
      )}

      {/* Sidebar Content */}
      <div className={`
        fixed left-0 top-0 bottom-0 bg-slate-900 z-50 transition-transform duration-300 w-64
        flex flex-col justify-between
        ${isOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div>
          <div className="h-16 flex items-center justify-between px-6 border-b border-slate-800">
            <div className="flex items-center">
              <div className="bg-gradient-to-br from-blue-600 to-indigo-600 p-1.5 rounded-lg">
                <LayoutDashboard className="w-5 h-5 text-white" />
              </div>
              <span className="ml-3 font-bold text-white text-lg">SalesIQ</span>
            </div>
            {/* Close button for mobile */}
            <button onClick={onClose} className="lg:hidden text-slate-400 hover:text-white">
              <X className="w-6 h-6" />
            </button>
          </div>

          <nav className="mt-8 px-2 space-y-2">
            <div className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Workspace</div>

            <button
              onClick={() => { onNavigate('COACH'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'COACH' 
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Mic className="w-5 h-5" />
              <span className="font-medium">Call Coach</span>
            </button>

            <button
              onClick={() => { onNavigate('DEAL'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'DEAL' 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Briefcase className="w-5 h-5" />
              <span className="font-medium">Deal Intelligence</span>
              <span className="ml-auto text-[10px] bg-indigo-500 text-white px-1.5 py-0.5 rounded font-bold">NEW</span>
            </button>

            <button
              onClick={() => { onNavigate('LIVE'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'LIVE' 
                  ? 'bg-rose-600 text-white shadow-lg shadow-rose-900/50' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Radio className="w-5 h-5" />
              <span className="font-medium">Live Assistant</span>
            </button>

            <button
              onClick={() => { onNavigate('QA'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'QA' 
                  ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <ShieldCheck className="w-5 h-5" />
              <span className="font-medium">Compliance QA</span>
            </button>

            <div className="px-4 text-xs font-semibold text-slate-500 uppercase tracking-wider mt-6 mb-2">History & Stats</div>

            <button
              onClick={() => { onNavigate('LIBRARY'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'LIBRARY' 
                  ? 'bg-slate-800 text-white' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <Library className="w-5 h-5" />
              <span className="font-medium">My Library</span>
            </button>

            <button
              onClick={() => { onNavigate('TRENDS'); onClose(); }}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                currentView === 'TRENDS' 
                  ? 'bg-slate-800 text-white' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <TrendingUp className="w-5 h-5" />
              <span className="font-medium">Performance Trends</span>
            </button>
          </nav>
        </div>

        <div className="p-4 border-t border-slate-800">
          <button className="w-full flex items-center gap-3 px-4 py-3 rounded-xl text-slate-400 hover:bg-slate-800 hover:text-white transition-all">
            <Settings className="w-5 h-5" />
            <span className="font-medium">Settings</span>
          </button>
        </div>
      </div>
    </>
  );
};

import React from 'react';
import { QABatchStats, QACallRecord } from '../../types';
import { CallAuditTable } from './CallAuditTable';
import { BarChart3, AlertOctagon, ShieldCheck, TrendingDown } from 'lucide-react';

interface QADashboardProps {
  stats: QABatchStats;
  calls: QACallRecord[];
}

export const QADashboard: React.FC<QADashboardProps> = ({ stats, calls }) => {
  return (
    <div className="space-y-6 animate-fade-in">
      {/* Top Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
         <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 flex flex-col justify-between">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Batch Average Score</h4>
            <div className="flex items-end gap-2">
              <span className={`text-4xl font-extrabold ${stats.averageScore >= 90 ? 'text-emerald-500' : 'text-amber-500'}`}>
                {stats.averageScore}
              </span>
              <span className="text-xs text-slate-400 mb-1.5">/ 100</span>
            </div>
         </div>

         <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 flex flex-col justify-between">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Critical Violations</h4>
            <div className="flex items-end gap-2">
              <span className="text-4xl font-extrabold text-red-500">
                {stats.criticalFlagCount}
              </span>
              <span className="text-xs text-slate-400 mb-1.5">calls flagged</span>
            </div>
         </div>

         <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 flex flex-col justify-between">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Clean Calls</h4>
            <div className="flex items-end gap-2">
               <span className="text-4xl font-extrabold text-emerald-500">
                {stats.totalCalls > 0 ? Math.round((stats.cleanCallCount / stats.totalCalls) * 100) : 0}%
              </span>
              <span className="text-xs text-slate-400 mb-1.5">pass rate</span>
            </div>
         </div>

         <div className="bg-white p-5 rounded-xl shadow-sm border border-slate-200 flex flex-col justify-between">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Calls Processed</h4>
            <div className="text-4xl font-extrabold text-blue-600">
               {stats.totalCalls}
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Top Violations Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 lg:col-span-2">
           <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
             <TrendingDown className="w-5 h-5 text-red-500" />
             Top Compliance Violations
           </h3>
           <div className="space-y-4">
             {(stats.topViolations || []).map((v, idx) => (
               <div key={idx}>
                 <div className="flex justify-between text-sm mb-1">
                   <span className="font-medium text-slate-700">"{v.phrase}"</span>
                   <span className="text-slate-500">{v.count} occurrences</span>
                 </div>
                 <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                    <div 
                      className="bg-red-500 h-2.5 rounded-full" 
                      style={{ width: `${stats.totalCalls > 0 ? (v.count / stats.totalCalls) * 100 : 0}%` }}
                    ></div>
                 </div>
               </div>
             ))}
             {(!stats.topViolations || stats.topViolations.length === 0) && (
               <div className="text-center text-slate-400 py-4 text-sm italic">No violations detected.</div>
             )}
           </div>
        </div>

        {/* Training Opportunities */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
           <h3 className="font-bold text-slate-800 mb-6 flex items-center gap-2">
             <AlertOctagon className="w-5 h-5 text-orange-500" />
             Training Needed
           </h3>
           <div className="space-y-4">
             {(stats.lowestPerformingReps || []).map((rep, idx) => (
               <div key={idx} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
                 <span className="font-bold text-slate-700 text-sm">{rep.name}</span>
                 <span className="text-xs font-bold text-red-600 bg-red-100 px-2 py-1 rounded">
                   Avg Score: {rep.avgScore}
                 </span>
               </div>
             ))}
             {(!stats.lowestPerformingReps || stats.lowestPerformingReps.length === 0) && (
                <div className="text-center text-slate-400 py-4 text-sm italic">No low performing reps.</div>
             )}
             <button className="w-full mt-4 py-2 text-xs font-bold text-blue-600 border border-blue-200 rounded-lg hover:bg-blue-50 transition-colors">
               Assign Coaching Modules
             </button>
           </div>
        </div>
      </div>

      {/* Audit List */}
      <CallAuditTable calls={calls} />
    </div>
  );
};

import React, { useState } from 'react';
import { QACallRecord, ViolationSeverity } from '../../types';
import { AlertCircle, CheckCircle2, AlertTriangle, ChevronDown, ChevronRight, Play, FileText, User, XCircle } from 'lucide-react';

interface CallAuditTableProps {
  calls: QACallRecord[];
}

export const CallAuditTable: React.FC<CallAuditTableProps> = ({ calls }) => {
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [filter, setFilter] = useState<'All' | 'Critical' | 'Review Needed' | 'Clean'>('All');

  const filteredCalls = filter === 'All' ? calls : (calls || []).filter(c => c.status === filter);

  const getSeverityColor = (sev: ViolationSeverity) => {
    switch (sev) {
      case 'Critical': return 'bg-red-100 text-red-800 border-red-200';
      case 'Warning': return 'bg-orange-100 text-orange-800 border-orange-200';
      case 'Info': return 'bg-blue-100 text-blue-800 border-blue-200';
    }
  };

  const getStatusBadge = (status: string) => {
    switch(status) {
      case 'Critical': return <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold bg-red-100 text-red-700"><XCircle className="w-3 h-3"/> Failed</span>;
      case 'Review Needed': return <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold bg-amber-100 text-amber-700"><AlertTriangle className="w-3 h-3"/> Review</span>;
      case 'Clean': return <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-bold bg-emerald-100 text-emerald-700"><CheckCircle2 className="w-3 h-3"/> Passed</span>;
      default: return null;
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Header & Filters */}
      <div className="p-6 border-b border-slate-100 flex justify-between items-center">
        <h3 className="font-bold text-slate-800 text-lg">Batch Audit Log</h3>
        <div className="flex gap-2">
          {['All', 'Critical', 'Review Needed', 'Clean'].map((f) => (
             <button 
               key={f}
               onClick={() => setFilter(f as any)}
               className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${filter === f ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
             >
               {f}
             </button>
          ))}
        </div>
      </div>

      {/* Table Header */}
      <div className="grid grid-cols-12 gap-4 px-6 py-3 bg-slate-50 border-b border-slate-200 text-xs font-bold text-slate-500 uppercase tracking-wider">
        <div className="col-span-4">Representative / File</div>
        <div className="col-span-2 text-center">Score</div>
        <div className="col-span-2">Violations</div>
        <div className="col-span-2">Scripts</div>
        <div className="col-span-2 text-right">Status</div>
      </div>

      {/* List */}
      <div className="max-h-[600px] overflow-y-auto">
        {(filteredCalls || []).map((call) => (
          <div key={call.id} className="border-b border-slate-100 last:border-0 hover:bg-slate-50/50 transition-colors">
            <div 
              className="grid grid-cols-12 gap-4 px-6 py-4 items-center cursor-pointer"
              onClick={() => setExpandedId(expandedId === call.id ? null : call.id)}
            >
              <div className="col-span-4">
                <div className="flex items-center gap-3">
                  <div className={`p-1 rounded transition-transform ${expandedId === call.id ? 'rotate-90' : ''}`}>
                    <ChevronRight className="w-4 h-4 text-slate-400" />
                  </div>
                  <div>
                    <p className="font-bold text-slate-800 text-sm">{call.repName}</p>
                    <p className="text-xs text-slate-500 font-mono">{call.filename} • {call.date}</p>
                  </div>
                </div>
              </div>

              <div className="col-span-2 text-center">
                 <span className={`text-lg font-bold ${call.qaScore < 70 ? 'text-red-600' : call.qaScore < 90 ? 'text-amber-500' : 'text-emerald-600'}`}>
                   {call.qaScore}
                 </span>
              </div>

              <div className="col-span-2">
                 {(call.violations || []).length > 0 ? (
                   <span className="text-xs font-medium text-red-600 bg-red-50 px-2 py-1 rounded border border-red-100">
                     {(call.violations || []).length} Detected
                   </span>
                 ) : (
                   <span className="text-xs text-slate-400">-</span>
                 )}
              </div>

              <div className="col-span-2">
                 {(call.missingRequiredScripts || []).length > 0 ? (
                   <span className="text-xs font-medium text-orange-600 bg-orange-50 px-2 py-1 rounded border border-orange-100">
                     {(call.missingRequiredScripts || []).length} Missing
                   </span>
                 ) : (
                   <span className="text-xs text-emerald-600 font-bold flex items-center gap-1">
                     <CheckCircle2 className="w-3 h-3" /> All Set
                   </span>
                 )}
              </div>

              <div className="col-span-2 text-right">
                {getStatusBadge(call.status)}
              </div>
            </div>

            {/* Expanded Details */}
            {expandedId === call.id && (
              <div className="px-14 pb-6 animate-fade-in bg-slate-50/50 border-t border-slate-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-4">
                  {/* Violations List */}
                  <div className="bg-white border border-slate-200 rounded-lg p-4 shadow-sm">
                    <h4 className="font-bold text-slate-700 text-sm mb-3 flex items-center gap-2">
                      <AlertCircle className="w-4 h-4 text-red-500" />
                      Phrase Violations
                    </h4>
                    {(call.violations || []).length === 0 ? (
                      <p className="text-xs text-slate-400 italic">No forbidden phrases detected.</p>
                    ) : (
                      <div className="space-y-3">
                        {(call.violations || []).map((v) => (
                          <div key={v.id} className="p-3 bg-red-50 rounded border border-red-100">
                            <div className="flex justify-between items-start mb-1">
                               <span className="font-bold text-red-800 text-xs uppercase">"{v.phrase}"</span>
                               <span className="font-mono text-[10px] text-red-500">{v.timestamp}</span>
                            </div>
                            <p className="text-xs text-slate-600 italic mb-2">"{v.contextSnippet}"</p>
                            <div className="text-xs bg-white p-2 rounded border border-red-100 text-slate-700">
                               <span className="font-bold text-emerald-600 block mb-0.5">Fix Suggestion:</span>
                               {v.suggestedFix}
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Missing Scripts */}
                  <div className="bg-white border border-slate-200 rounded-lg p-4 shadow-sm">
                    <h4 className="font-bold text-slate-700 text-sm mb-3 flex items-center gap-2">
                      <FileText className="w-4 h-4 text-blue-500" />
                      Required Scripts Check
                    </h4>
                    {(call.missingRequiredScripts || []).length === 0 ? (
                      <p className="text-xs text-slate-400 italic flex items-center gap-2">
                         <CheckCircle2 className="w-4 h-4 text-emerald-500" /> All mandatory statements found.
                      </p>
                    ) : (
                      <ul className="space-y-2">
                         {(call.missingRequiredScripts || []).map((script, idx) => (
                           <li key={idx} className="flex items-center gap-2 text-xs text-orange-700 bg-orange-50 p-2 rounded border border-orange-100">
                             <XCircle className="w-3.5 h-3.5 flex-shrink-0" />
                             Missing: "{script}"
                           </li>
                         ))}
                      </ul>
                    )}
                  </div>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { FileUpload } from './components/FileUpload';
import { TranscriptView } from './components/TranscriptView';
import { SentimentChart } from './components/SentimentChart';
import { CoachingCard } from './components/CoachingCard';
import { StatsOverview } from './components/StatsOverview';
import { TopicsChart } from './components/TopicsChart';
import { AudioPlayerBar } from './components/AudioPlayerBar';
import { FeedbackModal } from './components/FeedbackModal';
import { DealIntelligence } from './components/DealIntelligence';
import { CompliancePanel } from './components/CompliancePanel';
import { CustomerProfile } from './components/CustomerProfile';
import { CRMIntegration } from './components/CRMIntegration';
import { analyzeSalesCall, analyzeFullDeal } from './services/geminiService';
import { AppState, SalesAnalysisResult, SavedCall, DealInteraction, FullDealAnalysis } from './types';
import { Activity, RefreshCcw, Sparkles, MessageSquare, Menu, Save, Check, Layout, BrainCircuit, ListTodo, FileText, ShieldCheck, Download, ChevronDown, FileSpreadsheet, AlertTriangle } from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { QAModule } from './components/QAModule';
import { CallLibrary } from './components/library/CallLibrary';
import { TrendsDashboard } from './components/trends/TrendsDashboard';
import { LiveCopilot } from './components/live/LiveCopilot';
import { DealUpload } from './components/deal/DealUpload';
import { DealDashboard } from './components/deal/DealDashboard';
import { saveCall } from './services/storageService';
import { exportSingleCallReport } from './services/exportService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'COACH' | 'QA' | 'LIBRARY' | 'TRENDS' | 'LIVE' | 'DEAL'>('COACH');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // COACHING STATE
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<SalesAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [currentAudioTime, setCurrentAudioTime] = useState<number | null>(null);
  const [transcriptSearchTerm, setTranscriptSearchTerm] = useState('');
  const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [fileName, setFileName] = useState('');
  const [showExportMenu, setShowExportMenu] = useState(false);

  // DEAL STATE
  const [dealAnalysis, setDealAnalysis] = useState<FullDealAnalysis | null>(null);
  const [isDealAnalyzing, setIsDealAnalyzing] = useState(false);
  const [dealError, setDealError] = useState<string | null>(null);

  // TAB STATE
  const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'INTEL' | 'COACHING' | 'COMPLIANCE' | 'TRANSCRIPT'>('OVERVIEW');

  const handleFileSelect = async (file: File) => {
    setAppState(AppState.ANALYZING);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(0);
    setFileName(file.name);
    setIsSaved(false);

    if (audioUrl) URL.revokeObjectURL(audioUrl);
    const url = URL.createObjectURL(file);
    setAudioUrl(url);

    try {
      const data = await analyzeSalesCall(file);
      setResult(data);
      setAppState(AppState.COMPLETE);
      setActiveTab('OVERVIEW'); // Reset to overview on new file
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze the audio file.");
      setAppState(AppState.ERROR);
    }
  };

  const handleDealAnalyze = async (interactions: DealInteraction[]) => {
    setIsDealAnalyzing(true);
    setDealError(null);
    try {
      const result = await analyzeFullDeal(interactions);
      setDealAnalysis(result);
    } catch (e: any) {
      setDealError(e.message || "Deal analysis failed. Please try again.");
    } finally {
      setIsDealAnalyzing(false);
    }
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(null);
    setIsSaved(false);
    setShowExportMenu(false);
    if (audioUrl) {
      URL.revokeObjectURL(audioUrl);
      setAudioUrl(null);
    }
  };

  const handleSaveToLibrary = async () => {
    if (result && !isSaved) {
      try {
        await saveCall(result, fileName);
        setIsSaved(true);
      } catch (e) {
        console.error("Failed to save", e);
        alert("Failed to save to local library.");
      }
    }
  };

  const handleExportReport = (format: 'CSV' | 'PDF') => {
    if (result) {
      exportSingleCallReport(result, fileName, format);
      setShowExportMenu(false);
    }
  };

  const loadFromLibrary = (call: SavedCall) => {
    setResult(call.analysisData);
    setAppState(AppState.COMPLETE);
    setFileName(call.fileName);
    setIsSaved(true);
    setAudioUrl(null); // Audio blob is not stored in this version
    setCurrentView('COACH');
    setActiveTab('OVERVIEW');
  };

  const handleTopicClick = (topicName: string) => {
    setTranscriptSearchTerm(topicName);
    setActiveTab('TRANSCRIPT'); // Switch to transcript view
  };

  const handleTimestampClick = (time: number) => {
    setCurrentAudioTime(time);
  };

  // Render content based on active tab within COACH view
  const renderCoachTabs = () => {
    if (!result) return null;

    switch (activeTab) {
      case 'OVERVIEW':
        return (
          <div className="animate-fade-in space-y-8">
             <StatsOverview 
                stats={result.callStats} 
                ratio={result.talkRatio} 
                silence={result.silenceAnalysis}
              />
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                 {/* Explicit Height for Charts */}
                 <div className="h-[450px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
                    <SentimentChart 
                      data={result.sentimentGraph} 
                      highlightedTime={currentAudioTime} 
                    />
                 </div>
                 <div className="h-[450px]">
                    <TopicsChart topics={result.topics} competitors={result.competitors} onTopicClick={handleTopicClick} />
                 </div>
              </div>
              <CustomerProfile profile={result.customerProfile} followUp={result.followUp} />
          </div>
        );
      case 'INTEL':
        return (
          <div className="animate-fade-in space-y-8">
            <DealIntelligence 
              risk={result.dealIntelligence.riskAnalysis}
              committee={result.dealIntelligence.buyingCommittee}
              stage={result.dealIntelligence.dealStage}
              intents={result.dealIntelligence.intents}
            />
          </div>
        );
      case 'COMPLIANCE':
        return (
          <div className="animate-fade-in">
             <CompliancePanel compliance={result.compliance} />
          </div>
        );
      case 'COACHING':
        return (
          <div className="animate-fade-in">
             <CoachingCard coaching={result.coachingCard} />
          </div>
        );
      case 'TRANSCRIPT':
        return (
          <div className="animate-fade-in h-[calc(100vh-200px)]">
             <TranscriptView 
                transcript={result.transcript || []} 
                searchTerm={transcriptSearchTerm}
                onSearchChange={setTranscriptSearchTerm}
                onTimestampClick={handleTimestampClick}
                currentAudioTime={currentAudioTime}
              />
          </div>
        );
      default: return null;
    }
  };

  const renderContent = () => {
    switch(currentView) {
      case 'QA': return <QAModule />;
      case 'LIBRARY': return <CallLibrary onLoadCall={loadFromLibrary} />;
      case 'TRENDS': return <TrendsDashboard />;
      case 'LIVE': return <LiveCopilot />;
      case 'DEAL': return !dealAnalysis ? (
        <div className="animate-fade-in">
           {dealError && (
             <div className="max-w-4xl mx-auto mt-6 mb-4 p-4 bg-red-50 text-red-700 border border-red-200 rounded-xl flex items-start gap-3 shadow-sm">
               <AlertTriangle className="w-5 h-5 flex-shrink-0 mt-0.5" />
               <div>
                 <p className="font-bold">Analysis Failed</p>
                 <p className="text-sm opacity-90">{dealError}</p>
               </div>
             </div>
           )}
           <DealUpload onAnalyze={handleDealAnalyze} isAnalyzing={isDealAnalyzing} />
        </div>
      ) : (
        <div className="animate-fade-in">
           <button onClick={() => setDealAnalysis(null)} className="mb-4 text-sm text-slate-500 hover:text-blue-600 flex items-center gap-1 transition-colors">
             <RefreshCcw className="w-4 h-4" /> Start New Deal Analysis
           </button>
           <DealDashboard analysis={dealAnalysis} />
        </div>
      );
      default: return (
        <div className="max-w-7xl mx-auto space-y-6 pb-32">
             {/* Header for Single Call Mode */}
             <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4 mb-4">
                <div>
                   <h1 className="text-2xl font-bold text-slate-800">Sales Call Coach</h1>
                   <p className="text-slate-500">Single call analysis & deep intelligence.</p>
                </div>
                {appState === AppState.COMPLETE && result && (
                  <div className="flex items-center gap-2 self-start xl:self-auto flex-wrap">
                     <CRMIntegration data={result} />

                     {/* Export Dropdown */}
                     <div className="relative">
                        <button 
                          onClick={() => setShowExportMenu(!showExportMenu)}
                          className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold bg-white border border-slate-200"
                        >
                           <Download className="w-5 h-5" />
                           <span className="hidden sm:inline">Export Report</span>
                           <ChevronDown className="w-4 h-4" />
                        </button>
                        {showExportMenu && (
                          <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-slate-200 rounded-xl shadow-xl z-50 overflow-hidden animate-fade-in">
                            <button 
                              onClick={() => handleExportReport('PDF')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2 border-b border-slate-50"
                            >
                              <FileText className="w-4 h-4 text-red-600" /> PDF Report
                            </button>
                            <button 
                              onClick={() => handleExportReport('CSV')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                            >
                              <FileSpreadsheet className="w-4 h-4 text-green-600" /> Excel / CSV
                            </button>
                          </div>
                        )}
                     </div>

                     <button 
                       onClick={handleSaveToLibrary}
                       disabled={isSaved}
                       className={`p-2 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold ${isSaved ? 'text-emerald-600 bg-emerald-50 cursor-default' : 'text-slate-500 hover:text-blue-600 hover:bg-slate-100'}`}
                     >
                       {isSaved ? <Check className="w-5 h-5" /> : <Save className="w-5 h-5" />}
                       <span className="hidden sm:inline">{isSaved ? 'Saved to Vault' : 'Save to Library'}</span>
                     </button>
                     <button 
                        onClick={() => setIsFeedbackOpen(true)}
                        className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                      >
                        <MessageSquare className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={resetApp}
                        className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-blue-600 transition-colors bg-white border border-slate-200 px-3 py-2 rounded-lg"
                      >
                        <RefreshCcw className="w-4 h-4" />
                        <span className="hidden sm:inline">New Analysis</span>
                      </button>
                  </div>
                )}
             </div>

             {/* Tab Navigation */}
             {appState === AppState.COMPLETE && (
               <div className="flex border-b border-slate-200 mb-6 overflow-x-auto no-scrollbar">
                 <button 
                   onClick={() => setActiveTab('OVERVIEW')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'OVERVIEW' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <Layout className="w-4 h-4" /> Overview
                 </button>
                 <button 
                   onClick={() => setActiveTab('INTEL')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'INTEL' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <BrainCircuit className="w-4 h-4" /> Deal Intel
                 </button>
                 <button 
                   onClick={() => setActiveTab('COMPLIANCE')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COMPLIANCE' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ShieldCheck className="w-4 h-4" /> QA & Compliance
                 </button>
                 <button 
                   onClick={() => setActiveTab('COACHING')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COACHING' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ListTodo className="w-4 h-4" /> Coaching
                 </button>
                 <button 
                   onClick={() => setActiveTab('TRANSCRIPT')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'TRANSCRIPT' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <FileText className="w-4 h-4" /> Transcript
                 </button>
               </div>
             )}

             {/* Content */}
             {appState === AppState.IDLE || appState === AppState.ANALYZING || appState === AppState.ERROR ? (
                <div className="flex flex-col items-center justify-center min-h-[60vh]">
                   <div className="text-center mb-10 animate-fade-in-up px-4">
                     <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-bold mb-4 border border-blue-100">
                       <Sparkles className="w-3 h-3" />
                       <span>POWERED BY GEMINI 3.0 PRO</span>
                     </div>
                     <h2 className="text-4xl sm:text-5xl font-extrabold text-slate-900 mb-6 tracking-tight leading-tight">
                       Turn Sales Calls into <br/>
                       <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Revenue Science</span>
                     </h2>
                     <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                       Upload your sales recordings. Our AI engine extracts diarized transcripts, 
                       deal risks, buying committee maps, compliance scores, and follow-up emails in seconds.
                     </p>
                   </div>
                   <FileUpload onFileSelect={handleFileSelect} isAnalyzing={appState === AppState.ANALYZING} />

                   {appState === AppState.ERROR && (
                     <div className="mt-8 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 max-w-lg text-center shadow-sm mx-auto">
                       <p className="font-bold flex items-center justify-center gap-2">
                         Analysis Failed
                       </p>
                       <p className="text-sm mt-1">{error}</p>
                       <button onClick={resetApp} className="mt-3 text-xs font-bold uppercase tracking-wide text-red-800 hover:underline">Try Again</button>
                     </div>
                   )}
                </div>
              ) : null}

              {appState === AppState.COMPLETE && result && renderCoachTabs()}
          </div>
      );
    }
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans flex">
      {/* Sidebar Navigation */}
      <Sidebar 
        currentView={currentView} 
        onNavigate={setCurrentView} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      {/* Main Content Area */}
      <div className="flex-1 lg:ml-64 p-4 lg:p-8 transition-all duration-300 w-full overflow-hidden">

        {/* Mobile Header */}
        <div className="lg:hidden flex items-center justify-between mb-6">
           <div className="flex items-center gap-3">
             <button 
               onClick={() => setIsMobileMenuOpen(true)}
               className="p-2 text-slate-600 hover:bg-slate-200 rounded-lg"
             >
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-slate-800 text-lg">SalesIQ</span>
           </div>
        </div>

        {renderContent()}

        {/* Audio Player Bar (Only visible in COACH mode with audio) */}
        {currentView === 'COACH' && appState === AppState.COMPLETE && audioUrl && (
          <div className="lg:pl-64"> 
             <AudioPlayerBar 
               audioSrc={audioUrl} 
               onTimeUpdate={setCurrentAudioTime}
               externalCurrentTime={currentAudioTime}
             />
          </div>
        )}

        {/* Feedback Modal */}
        <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} />
      </div>
    </div>
  );
};

