                       className={`p-2 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold ${isSaved ? 'text-emerald-600 bg-emerald-50 cursor-default' : 'text-slate-500 hover:text-blue-600 hover:bg-slate-100'}`}
