             </div>
          </div>

          {/* Context Setup Form */}
          <div className={`bg-white rounded-xl border border-slate-200 shadow-sm transition-all duration-300 overflow-hidden flex-shrink-0 ${isContextCollapsed ? 'h-14 opacity-90' : 'h-auto p-5'}`}>
             <div 
