               <Square className="w-5 h-5" /> End Session
             </button>
           )}
           <button onClick={() => { disconnect(); setChunks([]); setSuggestionHistory([]); }} className="p-2 text-slate-400 hover:text-slate-600">
             <RotateCcw className="w-5 h-5" />
           </button>
        </div>
