import { GoogleGenAI, Type } from "@google/genai";
import { SalesAnalysisResult, LiveTranscriptChunk, ProspectProfile, DealInteraction, FullDealAnalysis } from "../types";

// Helper to convert File to Base64
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

// Helper: Sanitize JSON string from Gemini (strip markdown code blocks)
const cleanAndParseJSON = (text: string): any => {
  try {
    // 1. Try parsing directly
    return JSON.parse(text);
  } catch (e) {
    // 2. Try stripping markdown code blocks
    let cleaned = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();
    try {
      return JSON.parse(cleaned);
    } catch (e2) {
      // 3. Last ditch: If it ends unexpectedly, try to append closing braces (basic recovery for truncation)
      // This is a heuristic and might not work for complex nested structures
      console.warn("JSON Parse failed, attempting simple recovery for truncation...");
      if (cleaned.lastIndexOf('}') === -1 || cleaned.lastIndexOf(']') === -1) {
         // This is risky, but better than crashing if it's just a missing end brace
         // Not implementing full recovery here to avoid corrupt data, 
         // instead throwing specific error for UI to handle.
      }
      throw new Error("Failed to parse AI response. The model output was malformed JSON.");
    }
  }
};

// --- IMAGE GENERATION FOR AVATARS ---
const generateProspectAvatar = async (profile: ProspectProfile, apiKey: string): Promise<string | undefined> => {
  try {
    const ai = new GoogleGenAI({ apiKey });
    // Use gemini-2.5-flash-image for efficient generation
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{
          text: `Generate a flat, minimalist vector art avatar of a professional business person. 
                 Traits: ${profile.discType} personality, ${profile.communicationStyle} style. 
                 Expression should match a business setting. 
                 Use a solid, neutral background. High quality, professional headshot.`
        }]
      },
      config: {
        imageConfig: { aspectRatio: "1:1" }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return part.inlineData.data;
      }
    }
  } catch (e) {
    console.warn("Avatar generation failed:", e);
    return undefined;
  }
  return undefined;
};

