             </div>

             <div className={`grid grid-cols-1 md:grid-cols-3 gap-6 ${isContextCollapsed ? 'hidden' : 'block'}`}>
                {/* Pitch Card */}
                <div className="group">
                   <div className="flex items-center gap-2 mb-2">
