                   </div>
                   <textarea 
                     className="w-full p-3 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none resize-none h-24 bg-slate-50 focus:bg-white transition-colors" 
                     value={context.pitch}
