                   )}

                   {appState === AppState.ERROR && (
                     <div className="mt-8 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 max-w-lg text-center shadow-sm mx-auto">
                       <p className="font-bold flex items-center justify-center gap-2">
                         Analysis Failed
                       </p>
                       <p className="text-sm mt-1">{error}</p>
                       <button onClick={resetApp} className="mt-3 text-xs font-bold uppercase tracking-wide text-red-800 hover:underline">Try Again</button>
                     </div>
                   )}
                </div>
              ) : null}

              {appState === AppState.COMPLETE && result && renderCoachTabs()}
          </div>
      );
    }
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans flex">
      {/* Sidebar Navigation */}
      <Sidebar 
        currentView={currentView} 
        onNavigate={setCurrentView} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      {/* Thinking Overlay for Vibe */}
      <ThinkingOverlay isVisible={appState === AppState.ANALYZING} mode="CALL" />
      <ThinkingOverlay isVisible={isDealAnalyzing} mode="DEAL" />

      {/* Main Content Area */}
      <div className="flex-1 lg:ml-64 p-4 lg:p-8 transition-all duration-300 w-full overflow-hidden">

        {/* Mobile Header */}
        <div className="lg:hidden flex items-center justify-between mb-6">
           <div className="flex items-center gap-3">
             <button 
               onClick={() => setIsMobileMenuOpen(true)}
               className="p-2 text-slate-600 hover:bg-slate-200 rounded-lg"
             >
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-slate-800 text-lg">SalesIQ</span>
           </div>
        </div>

        {renderContent()}

        {/* Audio Player Bar (Only visible in COACH mode with audio) */}
        {currentView === 'COACH' && appState === AppState.COMPLETE && audioUrl && (
          <div className="lg:pl-64"> 
             <AudioPlayerBar 
               audioSrc={audioUrl} 
               onTimeUpdate={setCurrentAudioTime}
               externalCurrentTime={currentAudioTime}
             />
          </div>
        )}

        {/* Feedback Modal */}
        <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Video, Image as ImageIcon, Sparkles, Loader2, Download, AlertTriangle, Film, MonitorPlay, Smartphone } from 'lucide-react';

// Helper to convert File to Base64 (Local copy to avoid dependency issues)
const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const VideoGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [image, setImage] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('720p');

  const [status, setStatus] = useState<'IDLE' | 'CHECKING_KEY' | 'GENERATING' | 'COMPLETE' | 'ERROR'>('IDLE');
  const [loadingMessage, setLoadingMessage] = useState('');
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [generatedVideoUri, setGeneratedVideoUri] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const loadingMessages = [
    "Dreaming up pixels...",
    "Calculating light physics...",
    "Composing the scene...",
    "Rendering textures...",
    "Polishing frames...",
    "Applying cinematic grading..."
  ];

  useEffect(() => {
    let interval: any;
    if (status === 'GENERATING') {
      let i = 0;
      interval = setInterval(() => {
        setLoadingMessage(loadingMessages[i % loadingMessages.length]);
        i++;
      }, 4000);
    }
    return () => clearInterval(interval);
  }, [status]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImage(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const checkApiKeyAndGenerate = async () => {
    setErrorMsg(null);

    // 1. Check for Paid API Key selection (Required for Veo)
    try {
      const aistudio = (window as any).aistudio;
      if (aistudio && aistudio.hasSelectedApiKey && aistudio.openSelectKey) {
        const hasKey = await aistudio.hasSelectedApiKey();
        if (!hasKey) {
          setStatus('CHECKING_KEY');
          return; // Wait for user to select key
        }
      }
    } catch (e) {
      console.warn("AI Studio bridge not found, falling back to env key if available.");
    }

    startGeneration();
  };

  const handleOpenKeySelection = async () => {
    try {
      await (window as any).aistudio.openSelectKey();
      // Assume success after dialog interaction (Race condition mitigation)
      startGeneration();
    } catch (e) {
      setErrorMsg("Failed to open key selection dialog.");
      setStatus('IDLE');
    }
  };

  const startGeneration = async () => {
    setStatus('GENERATING');
    setVideoUrl(null);

    try {
      // Initialize AI with the specific environment key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let operation;
      const config = {
        numberOfVideos: 1,
        resolution: resolution,
        aspectRatio: aspectRatio,
        safetySettings: [
            { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_ONLY_HIGH' },
            { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_ONLY_HIGH' },
            { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_ONLY_HIGH' },
            { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_ONLY_HIGH' }
        ]
      };

      if (image) {
        const imageBase64 = await fileToBase64(image);
        operation = await ai.models.generateVideos({
          model: 'veo-3.1-fast-generate-preview',
          prompt: prompt,
          image: {
            imageBytes: imageBase64,
            mimeType: image.type,
          },
          config: config
        });
      } else {
        operation = await ai.models.generateVideos({
          model: 'veo-3.1-fast-generate-preview',
          prompt: prompt,
          config: config
        });
      }

      // Polling Loop
      while (!operation.done) {
        await new Promise(resolve => setTimeout(resolve, 5000)); // Poll every 5s
        operation = await ai.operations.getVideosOperation({ operation: operation });
        console.log("Veo Operation Status:", operation.metadata);
      }

      if (operation.error) {
        throw new Error(operation.error.message || "Video generation failed.");
      }

      const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (!videoUri) throw new Error("No video URI returned.");

      setGeneratedVideoUri(videoUri);

      // Fetch the actual video bytes using the API key
      const videoResponse = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
      if (!videoResponse.ok) throw new Error("Failed to download generated video.");

      const videoBlob = await videoResponse.blob();
      const localVideoUrl = URL.createObjectURL(videoBlob);

      setVideoUrl(localVideoUrl);
      setStatus('COMPLETE');

    } catch (e: any) {
      console.error(e);
      // Handle the specific "Requested entity was not found" error which implies stale key
      if (e.message?.includes("Requested entity was not found")) {
         setStatus('CHECKING_KEY');
         setErrorMsg("Session expired. Please re-select your API Key.");
      } else {
         setStatus('ERROR');
         setErrorMsg(e.message || "An unexpected error occurred during generation.");
      }
    }
  };

  return (
    <div className="max-w-6xl mx-auto animate-fade-in pb-20">
      <div className="mb-8">
        <h1 className="text-3xl font-extrabold text-slate-800 flex items-center gap-3">
          <Film className="w-8 h-8 text-rose-500" />
          AI Video Studio
          <span className="text-xs font-normal bg-rose-100 text-rose-700 px-2 py-1 rounded-full border border-rose-200">Veo 3.1 Fast</span>
        </h1>
        <p className="text-slate-500 mt-2 text-lg">Generate high-definition marketing videos for YouTube Shorts or Landscape.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* LEFT: Controls */}
        <div className="lg:col-span-1 space-y-6">

          {/* Prompt */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <label className="block text-sm font-bold text-slate-700 mb-2">Video Prompt</label>
            <textarea
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Describe the video you want to generate... (e.g., A cinematic drone shot of a futuristic neon city at night)"
              className="w-full h-32 p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-rose-500 focus:border-rose-500 outline-none text-sm resize-none bg-slate-50"
              disabled={status === 'GENERATING'}
            />
          </div>

          {/* Reference Image */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <label className="block text-sm font-bold text-slate-700 mb-2">Starting Image (Optional)</label>
            <div 
              onClick={() => status !== 'GENERATING' && fileInputRef.current?.click()}
              className={`
                border-2 border-dashed rounded-xl h-40 flex flex-col items-center justify-center cursor-pointer transition-all relative overflow-hidden
                ${status === 'GENERATING' ? 'opacity-50 cursor-not-allowed' : 'hover:border-rose-400 hover:bg-rose-50'}
                ${imagePreview ? 'border-rose-200' : 'border-slate-200'}
              `}
            >
              {imagePreview ? (
                <>
                  <img src={imagePreview} alt="Reference" className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 hover:opacity-100 transition-opacity">
                    <span className="text-white font-bold text-xs">Change Image</span>
                  </div>
                </>
              ) : (
                <div className="text-center text-slate-400">
                  <ImageIcon className="w-8 h-8 mx-auto mb-2" />
                  <span className="text-xs">Click to upload reference</span>
                </div>
              )}
              <input 
                ref={fileInputRef}
                type="file" 
                accept="image/*" 
                className="hidden" 
                onChange={handleImageUpload}
                disabled={status === 'GENERATING'}
              />
            </div>
          </div>

          {/* Settings */}
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
             <h3 className="text-sm font-bold text-slate-700 mb-4">Configuration</h3>

             <div className="space-y-4">
                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase mb-1.5">Aspect Ratio</label>
                  <div className="grid grid-cols-2 gap-2">
                    <button 
                      onClick={() => setAspectRatio('16:9')}
                      className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium border transition-all ${aspectRatio === '16:9' ? 'bg-rose-50 border-rose-500 text-rose-700' : 'border-slate-200 text-slate-600 hover:border-slate-300'}`}
                    >
                      <MonitorPlay className="w-4 h-4" /> 16:9 (YouTube)
                    </button>
                    <button 
                      onClick={() => setAspectRatio('9:16')}
                      className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium border transition-all ${aspectRatio === '9:16' ? 'bg-rose-50 border-rose-500 text-rose-700' : 'border-slate-200 text-slate-600 hover:border-slate-300'}`}
                    >
                      <Smartphone className="w-4 h-4" /> 9:16 (Shorts)
                    </button>
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-semibold text-slate-500 uppercase mb-1.5">Resolution</label>
                  <select 
                    value={resolution}
                    onChange={(e) => setResolution(e.target.value as any)}
                    className="w-full p-2 rounded-lg border border-slate-200 text-sm font-medium outline-none focus:border-rose-500"
                  >
                    <option value="720p">720p (Fast)</option>
                    <option value="1080p">1080p (HD)</option>
                  </select>
                </div>
             </div>
          </div>

          {/* Generate Button */}
          {status === 'CHECKING_KEY' ? (
             <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 text-center">
                <AlertTriangle className="w-8 h-8 text-amber-500 mx-auto mb-2" />
                <h4 className="font-bold text-amber-800 mb-1">Billing Account Required</h4>
                <p className="text-xs text-amber-700 mb-3">
                  Veo video generation requires a paid Google Cloud Project. Please select a project with billing enabled.
                </p>
                <button 
                  onClick={handleOpenKeySelection}
                  className="w-full bg-amber-500 hover:bg-amber-600 text-white font-bold py-2.5 rounded-lg transition-colors shadow-sm text-sm"
                >
                  Select Paid API Key
                </button>
                <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="block mt-2 text-[10px] text-amber-600 underline">
                  Learn about Gemini API billing
                </a>
             </div>
          ) : (
            <button 
              onClick={checkApiKeyAndGenerate}
              disabled={!prompt.trim() || status === 'GENERATING'}
              className="w-full bg-gradient-to-r from-rose-500 to-orange-500 hover:from-rose-600 hover:to-orange-600 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold py-4 rounded-xl shadow-lg shadow-rose-500/25 flex items-center justify-center gap-2 transition-all transform active:scale-95"
            >
              {status === 'GENERATING' ? (
                <><Loader2 className="w-5 h-5 animate-spin" /> Generating...</>
              ) : (
                <><Sparkles className="w-5 h-5" /> Generate Video</>
              )}
            </button>
          )}

          {errorMsg && (
            <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 flex items-start gap-2">
              <AlertTriangle className="w-4 h-4 flex-shrink-0 mt-0.5" />
              {errorMsg}
            </div>
          )}

        </div>

        {/* RIGHT: Output Stage */}
        <div className="lg:col-span-2 bg-slate-900 rounded-3xl overflow-hidden shadow-2xl relative flex flex-col min-h-[500px]">

           {status === 'IDLE' || status === 'CHECKING_KEY' ? (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 p-8 text-center">
                <div className="w-24 h-24 bg-slate-800 rounded-full flex items-center justify-center mb-6">
                   <Film className="w-10 h-10 text-slate-700" />
                </div>
                <h3 className="text-xl font-bold text-slate-500">Canvas Empty</h3>
                <p className="text-slate-600 max-w-xs mt-2">Enter a prompt and configure settings to start generating cinematic video.</p>
             </div>
           ) : null}

           {status === 'GENERATING' && (
             <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900 z-10 p-8 text-center">
                <div className="relative w-32 h-32 mb-8">
                   <div className="absolute inset-0 border-4 border-rose-500/20 rounded-full"></div>
                   <div className="absolute inset-0 border-4 border-rose-500 rounded-full border-t-transparent animate-spin"></div>
                   <div className="absolute inset-0 flex items-center justify-center">
                      <Sparkles className="w-10 h-10 text-rose-500 animate-pulse" />
                   </div>
                </div>
                <h3 className="text-2xl font-bold text-white mb-2 animate-pulse">Creating Video</h3>
                <p className="text-rose-400 font-mono text-sm">{loadingMessage}</p>
                <div className="mt-8 px-6 py-2 bg-slate-800 rounded-full border border-slate-700 text-xs text-slate-400">
                  This may take 1-2 minutes. Please don't close the tab.
                </div>
             </div>
           )}

           {status === 'COMPLETE' && videoUrl && (
             <div className="flex flex-col h-full bg-black">
                <div className="flex-grow flex items-center justify-center bg-black relative">
                   <video 
                     src={videoUrl} 
                     controls 
                     autoPlay 
                     loop 
                     className="max-h-full max-w-full shadow-2xl"
                     style={{ aspectRatio: aspectRatio === '16:9' ? '16/9' : '9/16' }}
                   />
                </div>
                <div className="bg-slate-900 p-6 border-t border-slate-800 flex justify-between items-center">
                   <div>
                     <p className="text-white font-bold text-lg mb-1">Generation Complete</p>
                     <p className="text-slate-400 text-xs">Veo 3.1 • {resolution} • {aspectRatio}</p>
                   </div>
                   <a 
                     href={videoUrl} 
                     download={`veo-generation-${Date.now()}.mp4`}
                     className="flex items-center gap-2 bg-white text-black hover:bg-slate-200 px-6 py-3 rounded-xl font-bold transition-colors"
                   >
                     <Download className="w-5 h-5" /> Download MP4
                   </a>
                </div>
             </div>
           )}

           {status === 'ERROR' && (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400 p-8 text-center bg-slate-900">
                <div className="w-20 h-20 bg-red-900/20 rounded-full flex items-center justify-center mb-4 border border-red-500/20">
                   <AlertTriangle className="w-10 h-10 text-red-500" />
                </div>
                <h3 className="text-xl font-bold text-red-400">Generation Failed</h3>
                <p className="text-slate-500 max-w-md mt-2 mb-6">{errorMsg}</p>
                <button 
                  onClick={() => setStatus('IDLE')}
                  className="px-6 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-lg text-white font-medium transition-all"
                >
                  Try Again
                </button>
             </div>
           )}

        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { FileUpload } from './components/FileUpload';
import { TranscriptView } from './components/TranscriptView';
import { SentimentChart } from './components/SentimentChart';
import { CoachingCard } from './components/CoachingCard';
import { StatsOverview } from './components/StatsOverview';
import { TopicsChart } from './components/TopicsChart';
import { AudioPlayerBar } from './components/AudioPlayerBar';
import { FeedbackModal } from './components/FeedbackModal';
import { DealIntelligence } from './components/DealIntelligence';
import { CompliancePanel } from './components/CompliancePanel';
import { CustomerProfile } from './components/CustomerProfile';
import { CRMIntegration } from './components/CRMIntegration';
import { ThinkingOverlay } from './components/ThinkingOverlay';
import { analyzeSalesCall, analyzeFullDeal } from './services/geminiService';
import { AppState, SalesAnalysisResult, SavedCall, DealInteraction, FullDealAnalysis } from './types';
import { Activity, RefreshCcw, Sparkles, MessageSquare, Menu, Save, Check, Layout, BrainCircuit, ListTodo, FileText, ShieldCheck, Download, ChevronDown, FileSpreadsheet, AlertTriangle, PlayCircle } from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { QAModule } from './components/QAModule';
import { CallLibrary } from './components/library/CallLibrary';
import { TrendsDashboard } from './components/trends/TrendsDashboard';
import { LiveCopilot } from './components/live/LiveCopilot';
import { DealUpload } from './components/deal/DealUpload';
import { DealDashboard } from './components/deal/DealDashboard';
import { VideoGenerator } from './components/video/VideoGenerator';
import { exportSingleCallReport } from './services/exportService'; 
import { saveCall as saveCallToDb, seedDemoCalls, getAllCalls, getDemoDealAnalysis } from './services/storageService'; 

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'COACH' | 'QA' | 'LIBRARY' | 'TRENDS' | 'LIVE' | 'DEAL' | 'VIDEO'>('COACH');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // COACHING STATE
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [result, setResult] = useState<SalesAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [currentAudioTime, setCurrentAudioTime] = useState<number | null>(null);
  const [transcriptSearchTerm, setTranscriptSearchTerm] = useState('');
  const [isFeedbackOpen, setIsFeedbackOpen] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [fileName, setFileName] = useState('');
  const [showExportMenu, setShowExportMenu] = useState(false);

  // DEAL STATE
  const [dealAnalysis, setDealAnalysis] = useState<FullDealAnalysis | null>(null);
  const [isDealAnalyzing, setIsDealAnalyzing] = useState(false);
  const [dealError, setDealError] = useState<string | null>(null);

  // TAB STATE
  const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'INTEL' | 'COACHING' | 'COMPLIANCE' | 'TRANSCRIPT'>('OVERVIEW');

  const handleFileSelect = async (file: File) => {
    setAppState(AppState.ANALYZING);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(0);
    setFileName(file.name);
    setIsSaved(false);

    if (audioUrl) URL.revokeObjectURL(audioUrl);
    const url = URL.createObjectURL(file);
    setAudioUrl(url);

    try {
      const data = await analyzeSalesCall(file);
      setResult(data);
      setAppState(AppState.COMPLETE);
      setActiveTab('OVERVIEW'); // Reset to overview on new file
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze the audio file.");
      setAppState(AppState.ERROR);
    }
  };

  const handleLoadDemo = async () => {
    setAppState(AppState.ANALYZING);
    setError(null);

    try {
      await seedDemoCalls();
      const calls = await getAllCalls();
      const demoCall = calls.find(c => c.fileName.includes('Discovery')) || calls[0];

      // REDUCED TIMER TO 1000ms FOR SMOOTHER VIDEO FLOW
      setTimeout(() => {
        if (demoCall) {
          setResult(demoCall.analysisData);
          setFileName(demoCall.fileName);
          setIsSaved(true);
          setAppState(AppState.COMPLETE);
          setActiveTab('OVERVIEW');
          setAudioUrl(null); // No audio for demo
        } else {
          setError("Could not load demo data.");
          setAppState(AppState.ERROR);
        }
      }, 1000);
    } catch (e) {
      console.error(e);
      setError("Failed to load demo.");
      setAppState(AppState.ERROR);
    }
  };

  const handleDealAnalyze = async (interactions: DealInteraction[]) => {
    setIsDealAnalyzing(true);
    setDealError(null);
    try {
      const result = await analyzeFullDeal(interactions);
      setDealAnalysis(result);
    } catch (e: any) {
      setDealError(e.message || "Deal analysis failed. Please try again.");
    } finally {
      setIsDealAnalyzing(false);
    }
  };

  const handleLoadDemoDeal = () => {
    setIsDealAnalyzing(true);
    setDealError(null);
    // REDUCED TIMER TO 1200ms FOR SMOOTHER VIDEO FLOW
    setTimeout(() => {
        const demoData = getDemoDealAnalysis();
        setDealAnalysis(demoData);
        setIsDealAnalyzing(false);
    }, 1200);
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setResult(null);
    setError(null);
    setTranscriptSearchTerm('');
    setCurrentAudioTime(null);
    setIsSaved(false);
    setShowExportMenu(false);
    if (audioUrl) {
      URL.revokeObjectURL(audioUrl);
      setAudioUrl(null);
    }
  };

  const handleSaveToLibrary = async () => {
    if (result && !isSaved) {
      try {
        await saveCallToDb(result, fileName);
        setIsSaved(true);
      } catch (e) {
        console.error("Failed to save", e);
        alert("Failed to save to local library.");
      }
    }
  };

  const handleExportReport = (format: 'CSV' | 'PDF') => {
    if (result) {
      exportSingleCallReport(result, fileName, format);
      setShowExportMenu(false);
    }
  };

  const loadFromLibrary = (call: SavedCall) => {
    setResult(call.analysisData);
    setAppState(AppState.COMPLETE);
    setFileName(call.fileName);
    setIsSaved(true);
    setAudioUrl(null); // Audio blob is not stored in this version
    setCurrentView('COACH');
    setActiveTab('OVERVIEW');
  };

  const handleTopicClick = (topicName: string) => {
    setTranscriptSearchTerm(topicName);
    setActiveTab('TRANSCRIPT'); // Switch to transcript view
  };

  const handleTimestampClick = (time: number) => {
    setCurrentAudioTime(time);
  };

  // Render content based on active tab within COACH view
  const renderCoachTabs = () => {
    if (!result) return null;

    switch (activeTab) {
      case 'OVERVIEW':
        return (
          <div className="animate-fade-in space-y-8">
             <StatsOverview 
                stats={result.callStats} 
                ratio={result.talkRatio} 
                silence={result.silenceAnalysis}
              />
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                 {/* Explicit Height for Charts */}
                 <div className="h-[450px] bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
                    <SentimentChart 
                      data={result.sentimentGraph} 
                      highlightedTime={currentAudioTime} 
                    />
                 </div>
                 <div className="h-[450px]">
                    <TopicsChart topics={result.topics} competitors={result.competitors} onTopicClick={handleTopicClick} />
                 </div>
              </div>
              <CustomerProfile profile={result.customerProfile} followUp={result.followUp} />
          </div>
        );
      case 'INTEL':
        return (
          <div className="animate-fade-in space-y-8">
            <DealIntelligence 
              risk={result.dealIntelligence.riskAnalysis}
              committee={result.dealIntelligence.buyingCommittee}
              stage={result.dealIntelligence.dealStage}
              intents={result.dealIntelligence.intents}
            />
          </div>
        );
      case 'COMPLIANCE':
        return (
          <div className="animate-fade-in">
             <CompliancePanel compliance={result.compliance} />
          </div>
        );
      case 'COACHING':
        return (
          <div className="animate-fade-in">
             <CoachingCard coaching={result.coachingCard} />
          </div>
        );
      case 'TRANSCRIPT':
        return (
          <div className="animate-fade-in h-[calc(100vh-200px)]">
             <TranscriptView 
                transcript={result.transcript || []} 
                searchTerm={transcriptSearchTerm}
                onSearchChange={setTranscriptSearchTerm}
                onTimestampClick={handleTimestampClick}
                currentAudioTime={currentAudioTime}
              />
          </div>
        );
      default: return null;
    }
  };

  const renderContent = () => {
    switch(currentView) {
      case 'QA': return <QAModule />;
      case 'LIBRARY': return <CallLibrary onLoadCall={loadFromLibrary} />;
      case 'TRENDS': return <TrendsDashboard />;
      case 'LIVE': return <LiveCopilot />;
      case 'VIDEO': return <VideoGenerator />;
      case 'DEAL': return !dealAnalysis ? (
        <div className="animate-fade-in">
           {dealError && (
             <div className="max-w-4xl mx-auto mt-6 mb-4 p-4 bg-red-50 text-red-700 border border-red-200 rounded-xl flex items-start gap-3 shadow-sm">
               <AlertTriangle className="w-5 h-5 flex-shrink-0 mt-0.5" />
               <div>
                 <p className="font-bold">Analysis Failed</p>
                 <p className="text-sm opacity-90">{dealError}</p>
               </div>
             </div>
           )}
           <DealUpload 
             onAnalyze={handleDealAnalyze} 
             isAnalyzing={isDealAnalyzing} 
             onLoadDemo={handleLoadDemoDeal}
           />
        </div>
      ) : (
        <div className="animate-fade-in">
           <button onClick={() => setDealAnalysis(null)} className="mb-4 text-sm text-slate-500 hover:text-blue-600 flex items-center gap-1 transition-colors">
             <RefreshCcw className="w-4 h-4" /> Start New Deal Analysis
           </button>
           <DealDashboard analysis={dealAnalysis} />
        </div>
      );
      default: return (
        <div className="max-w-7xl mx-auto space-y-6 pb-32">
             {/* Header for Single Call Mode */}
             <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-4 mb-4">
                <div>
                   <h1 className="text-2xl font-bold text-slate-800">Sales Call Coach</h1>
                   <p className="text-slate-500">Single call analysis & deep intelligence.</p>
                </div>
                {appState === AppState.COMPLETE && result && (
                  <div className="flex items-center gap-2 self-start xl:self-auto flex-wrap">
                     <CRMIntegration data={result} />

                     {/* Export Dropdown */}
                     <div className="relative">
                        <button 
                          onClick={() => setShowExportMenu(!showExportMenu)}
                          className="p-2 text-slate-500 hover:text-blue-600 hover:bg-slate-100 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold bg-white border border-slate-200"
                        >
                           <Download className="w-5 h-5" />
                           <span className="hidden sm:inline">Export Report</span>
                           <ChevronDown className="w-4 h-4" />
                        </button>
                        {showExportMenu && (
                          <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-slate-200 rounded-xl shadow-xl z-50 overflow-hidden animate-fade-in">
                            <button 
                              onClick={() => handleExportReport('PDF')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2 border-b border-slate-50"
                            >
                              <FileText className="w-4 h-4 text-red-600" /> PDF Report
                            </button>
                            <button 
                              onClick={() => handleExportReport('CSV')}
                              className="w-full text-left px-4 py-3 text-sm text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                            >
                              <FileSpreadsheet className="w-4 h-4 text-green-600" /> Excel / CSV
                            </button>
                          </div>
                        )}
                     </div>

                     <button 
                       onClick={handleSaveToLibrary}
                       disabled={isSaved}
                       className={`p-2 transition-colors rounded-lg flex items-center gap-2 text-sm font-bold ${isSaved ? 'text-emerald-600 bg-emerald-50 cursor-default' : 'text-slate-500 hover:text-blue-600 hover:bg-slate-100'}`}
                     >
                       {isSaved ? <Check className="w-5 h-5" /> : <Save className="w-5 h-5" />}
                       <span className="hidden sm:inline">{isSaved ? 'Saved to Vault' : 'Save to Library'}</span>
                     </button>
                     <button 
                        onClick={() => setIsFeedbackOpen(true)}
                        className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                      >
                        <MessageSquare className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={resetApp}
                        className="flex items-center gap-2 text-sm font-medium text-slate-500 hover:text-blue-600 transition-colors bg-white border border-slate-200 px-3 py-2 rounded-lg"
                      >
                        <RefreshCcw className="w-4 h-4" />
                        <span className="hidden sm:inline">New Analysis</span>
                      </button>
                  </div>
                )}
             </div>

             {/* Tab Navigation */}
             {appState === AppState.COMPLETE && (
               <div className="flex border-b border-slate-200 mb-6 overflow-x-auto no-scrollbar">
                 <button 
                   onClick={() => setActiveTab('OVERVIEW')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'OVERVIEW' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <Layout className="w-4 h-4" /> Overview
                 </button>
                 <button 
                   onClick={() => setActiveTab('INTEL')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'INTEL' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <BrainCircuit className="w-4 h-4" /> Deal Intel
                 </button>
                 <button 
                   onClick={() => setActiveTab('COMPLIANCE')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COMPLIANCE' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ShieldCheck className="w-4 h-4" /> QA & Compliance
                 </button>
                 <button 
                   onClick={() => setActiveTab('COACHING')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'COACHING' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <ListTodo className="w-4 h-4" /> Coaching
                 </button>
                 <button 
                   onClick={() => setActiveTab('TRANSCRIPT')}
                   className={`flex items-center gap-2 px-6 py-3 text-sm font-bold border-b-2 transition-colors whitespace-nowrap ${activeTab === 'TRANSCRIPT' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                 >
                   <FileText className="w-4 h-4" /> Transcript
                 </button>
               </div>
             )}

             {/* Content */}
             {appState === AppState.IDLE || appState === AppState.ANALYZING || appState === AppState.ERROR ? (
                <div className="flex flex-col items-center justify-center min-h-[60vh]">
                   <div className="text-center mb-10 animate-fade-in-up px-4">
                     <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-bold mb-4 border border-blue-100">
                       <Sparkles className="w-3 h-3" />
                       <span>POWERED BY GEMINI 2.5 FLASH & PRO</span>
                     </div>
                     <h2 className="text-4xl sm:text-5xl font-extrabold text-slate-900 mb-6 tracking-tight leading-tight">
                       Turn Sales Calls into <br/>
                       <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-indigo-600">Revenue Science</span>
                     </h2>
                     <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                       Upload your sales recordings. Our AI engine extracts diarized transcripts, 
                       deal risks, buying committee maps, compliance scores, and follow-up emails in seconds.
                     </p>
                   </div>
                   <FileUpload onFileSelect={handleFileSelect} isAnalyzing={appState === AppState.ANALYZING} />

                   {/* DEMO BUTTON */}
                   {appState === AppState.IDLE && (
                      <button 
                        onClick={handleLoadDemo}
                        className="mt-6 flex items-center gap-2 text-slate-500 hover:text-blue-600 bg-white border border-slate-200 hover:border-blue-300 px-5 py-2.5 rounded-full shadow-sm hover:shadow-md transition-all font-semibold text-sm animate-fade-in-up"
                        style={{ animationDelay: '0.2s' }}
                      >
                        <PlayCircle className="w-4 h-4" />
                        Try Demo Analysis (No File Needed)
                      </button>
                   )}

                   {appState === AppState.ERROR && (
                     <div className="mt-8 p-4 bg-red-50 border border-red-200 rounded-lg text-red-700 max-w-lg text-center shadow-sm mx-auto">
                       <p className="font-bold flex items-center justify-center gap-2">
                         Analysis Failed
                       </p>
                       <p className="text-sm mt-1">{error}</p>
                       <button onClick={resetApp} className="mt-3 text-xs font-bold uppercase tracking-wide text-red-800 hover:underline">Try Again</button>
                     </div>
                   )}
                </div>
              ) : null}

              {appState === AppState.COMPLETE && result && renderCoachTabs()}
          </div>
      );
    }
  };

  return (
    <div className="bg-slate-50 min-h-screen font-sans flex">
      {/* Sidebar Navigation */}
      <Sidebar 
        currentView={currentView} 
        onNavigate={setCurrentView} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      {/* Thinking Overlay for Vibe */}
      <ThinkingOverlay isVisible={appState === AppState.ANALYZING} mode="CALL" />
      <ThinkingOverlay isVisible={isDealAnalyzing} mode="DEAL" />

      {/* Main Content Area */}
      <div className="flex-1 lg:ml-64 p-4 lg:p-8 transition-all duration-300 w-full overflow-hidden">

        {/* Mobile Header */}
        <div className="lg:hidden flex items-center justify-between mb-6">
           <div className="flex items-center gap-3">
             <button 
               onClick={() => setIsMobileMenuOpen(true)}
               className="p-2 text-slate-600 hover:bg-slate-200 rounded-lg"
             >
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-slate-800 text-lg">SalesIQ</span>
           </div>
        </div>

        {renderContent()}

        {/* Audio Player Bar (Only visible in COACH mode with audio) */}
        {currentView === 'COACH' && appState === AppState.COMPLETE && audioUrl && (
          <div className="lg:pl-64"> 
             <AudioPlayerBar 
               audioSrc={audioUrl} 
               onTimeUpdate={setCurrentAudioTime}
               externalCurrentTime={currentAudioTime}
             />
          </div>
        )}

        {/* Feedback Modal */}
        <FeedbackModal isOpen={isFeedbackOpen} onClose={() => setIsFeedbackOpen(false)} />
      </div>
    </div>
  );
};

export default App;

