  const getIntentStyles = (category: string) => {
    switch(category) {
      case 'Buying': return { bg: 'bg-emerald-50', border: 'border-emerald-100', bar: 'bg-emerald-500', icon: <Target className="w-4 h-4 text-emerald-600" /> };
      case 'Pricing': return { bg: 'bg-blue-50', border: 'border-blue-100', bar: 'bg-blue-500', icon: <DollarSign className="w-4 h-4 text-blue-600" /> };
      case 'Risk': return { bg: 'bg-red-50', border: 'border-red-100', bar: 'bg-red-500', icon: <AlertTriangle className="w-4 h-4 text-red-600" /> };
      case 'Timeline': return { bg: 'bg-purple-50', border: 'border-purple-100', bar: 'bg-purple-500', icon: <Clock className="w-4 h-4 text-purple-600" /> };
      case 'Feature Fit': return { bg: 'bg-indigo-50', border: 'border-indigo-100', bar: 'bg-indigo-500', icon: <Search className="w-4 h-4 text-indigo-600" /> };
      default: return { bg: 'bg-slate-50', border: 'border-slate-200', bar: 'bg-slate-400', icon: <Briefcase className="w-4 h-4 text-slate-500" /> };
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 mb-8">

