         </div>
         <div className="space-y-3 flex-grow overflow-y-auto max-h-[250px] custom-scrollbar pr-1">
            {(intents || []).map((intent, idx) => {
              const styles = getIntentStyles(intent.category);
              return (
                <div key={idx} className={`p-3 rounded-lg border ${styles.bg} ${styles.border}`}>
                   <div className="flex justify-between items-center mb-2">
                      <div className="flex items-center gap-2">
                         {styles.icon}
                         <span className="text-xs font-bold uppercase text-slate-700">{intent.category}</span>
                      </div>
                      <span className="text-xs font-mono font-bold text-slate-600">{intent.score}%</span>
                   </div>

                   <div className="w-full h-1.5 bg-white/60 rounded-full overflow-hidden mb-2">
                      <div className={`h-full ${styles.bar}`} style={{ width: `${intent.score}%` }}></div>
                   </div>

                   <div className="bg-white/50 p-2 rounded border border-black/5 text-[10px] text-slate-600 italic leading-tight">
                     "{intent.evidence}"
