// Helper for standard fetch handling
const handleResponse = async (response: Response) => {
  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`API Error: ${response.status} ${errorText}`);
  }
  return response.json();
};

export const api = {
  // --- CALLS ---

  async analyzeCall(file: File): Promise<SalesAnalysisResult> {
    const formData = new FormData();
    formData.append('audio', file);

    const response = await fetch(`${API_BASE_URL}/analyze/call`, {
      method: 'POST',
      body: formData,
    });
    return handleResponse(response);
  },

  async saveCall(data: SavedCall): Promise<void> {
    const response = await fetch(`${API_BASE_URL}/calls`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return handleResponse(response);
  },

  async getCalls(): Promise<SavedCall[]> {
    const response = await fetch(`${API_BASE_URL}/calls`);
    return handleResponse(response);
  },

  async deleteCall(id: string): Promise<void> {
    const response = await fetch(`${API_BASE_URL}/calls/${id}`, {
      method: 'DELETE',
    });
    return handleResponse(response);
  },

  async updateCall(id: string, updates: Partial<SavedCall>): Promise<void> {
    const response = await fetch(`${API_BASE_URL}/calls/${id}`, {
      method: 'PATCH',
