                      items: {
                          type: Type.OBJECT,
                          properties: {
                              category: { type: Type.STRING, enum: ["Buying", "Pricing", "Timeline", "Feature Fit", "Risk"] },
                              score: { type: Type.NUMBER },
                              evidence: { type: Type.STRING }
                          }
                      }
                  }
              }
            },
            silenceAnalysis: {
              type: Type.OBJECT,
              properties: {
                listeningRatio: { type: Type.NUMBER },
                smartSilenceCount: { type: Type.NUMBER },
                awkwardSilenceCount: { type: Type.NUMBER },
                explanation: { type: Type.STRING }
              }
            },
            compliance: {
              type: Type.OBJECT,
              properties: {
                complianceScore: { type: Type.NUMBER },
                forbiddenPhrasesDetected: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      phrase: { type: Type.STRING },
                      context: { type: Type.STRING },
                      severity: { type: Type.STRING, enum: ["Critical", "Warning"] },
                      correction: { type: Type.STRING }
                    }
                  }
                },
                requiredStatements: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      statement: { type: Type.STRING },
                      status: { type: Type.STRING, enum: ["Present", "Missing"] }
                    }
                  }
                }
              }
            },
            customerProfile: {
              type: Type.OBJECT,
              properties: {
                discType: { type: Type.STRING, enum: ["Dominance", "Influence", "Steadiness", "Conscientiousness"] },
                communicationStyle: { type: Type.STRING },
                sellingTips: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            },
            followUp: {
              type: Type.OBJECT,
              properties: {
                emailSubject: { type: Type.STRING },
                emailBody: { type: Type.STRING },
                agendaItems: { type: Type.ARRAY, items: { type: Type.STRING } },
                emailVariations: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      tone: { type: Type.STRING, enum: ["Professional", "Friendly", "Urgent"] },
                      subject: { type: Type.STRING },
                      body: { type: Type.STRING }
                    }
                  }
                },
                proposalBullets: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini.");

    try {
      const json = safeJSONParse(text) as SalesAnalysisResult;

      if (json.customerProfile) {
         const avatarBase64 = await generateProspectAvatar(json.customerProfile, apiKey);
         if (avatarBase64) {
           json.customerProfile.avatarBase64 = avatarBase64;
         }
      }

      return json;
    } catch (error) {
      console.error("Failed to parse JSON response:", text);
      throw new Error("Invalid JSON response from AI model.");
    }
  } catch (err: any) {
    console.error("Call Analysis Error:", err);
    throw new Error(err.message || "Call analysis failed. Please check your API key or try a shorter audio file.");
  }
};

// --- AUDIO UTILS FOR LIVE API ---

export const blobToPCM = async (blob: Blob): Promise<Int16Array> => {
    const arrayBuffer = await blob.arrayBuffer();
    const audioContext = new AudioContext({ sampleRate: 16000 });
    const audioBuffer = await audioContext.decodeAudioData(arrayBuffer);
    const float32Data = audioBuffer.getChannelData(0);

    // Downsample or convert Float32 to Int16
    const int16Data = new Int16Array(float32Data.length);
    for (let i = 0; i < float32Data.length; i++) {
        const s = Math.max(-1, Math.min(1, float32Data[i]));
        int16Data[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return int16Data;
};

export const b64ToUint8Array = (base64: string): Uint8Array => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
};

export const arrayBufferToBase64 = (buffer: ArrayBuffer): string => {
    let binary = '';
    const bytes = new Uint8Array(buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
};

export const float32ToInt16 = (float32: Float32Array): Int16Array => {
    const int16 = new Int16Array(float32.length);
    for (let i = 0; i < float32.length; i++) {
        const s = Math.max(-1, Math.min(1, float32[i]));
        int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return int16;
};

import { SavedCall, SalesAnalysisResult, SavedDeal, FullDealAnalysis } from '../types';
import { USE_BACKEND } from '../config';
import { api } from './api';

const DB_NAME = 'SalesIQ_DB';
const STORE_NAME = 'saved_calls';
const DEAL_STORE_NAME = 'saved_deals';
const DB_VERSION = 2;

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = (event) => reject("Database error: " + (event.target as any).errorCode);
    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(DEAL_STORE_NAME)) {
        db.createObjectStore(DEAL_STORE_NAME, { keyPath: 'id' });
      }
    };
    request.onsuccess = (event) => resolve((event.target as IDBOpenDBRequest).result);
  });
};

export const saveCall = async (analysis: SalesAnalysisResult, fileName: string): Promise<void> => {
  const call: SavedCall = {
    id: crypto.randomUUID(),
    fileName,
    dateSaved: Date.now(),
    summary: analysis.coachingCard.overallSummary,
    stats: analysis.callStats,
    analysisData: analysis,
    isExemplar: false
  };

  // --- BACKEND MODE ---
  if (USE_BACKEND) {
    return api.saveCall(call);
  }

  // --- LOCAL MODE ---
  const db = await initDB();
  const tx = db.transaction(STORE_NAME, 'readwrite');
  const store = tx.objectStore(STORE_NAME);
  store.put(call);
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
};

export const updateCall = async (id: string, updates: Partial<SavedCall>): Promise<void> => {
  // --- BACKEND MODE ---
  if (USE_BACKEND) {
    return api.updateCall(id, updates);
  }

  // --- LOCAL MODE ---
  const db = await initDB();
  const tx = db.transaction(STORE_NAME, 'readwrite');
  const store = tx.objectStore(STORE_NAME);
  const request = store.get(id);

  return new Promise((resolve, reject) => {
    request.onsuccess = () => {
      const data = request.result as SavedCall;
      if (!data) return reject("Call not found");
      const updatedData = { ...data, ...updates };
      const updateRequest = store.put(updatedData);
      updateRequest.onsuccess = () => resolve();
      updateRequest.onerror = () => reject(updateRequest.error);
    };
    request.onerror = () => reject(request.error);
  });
};

export const getAllCalls = async (): Promise<SavedCall[]> => {
  // --- BACKEND MODE ---
  if (USE_BACKEND) {
    return api.getCalls();
  }

  // --- LOCAL MODE ---
  const db = await initDB();
  const tx = db.transaction(STORE_NAME, 'readonly');
  const store = tx.objectStore(STORE_NAME);
  const request = store.getAll();
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const deleteCall = async (id: string): Promise<void> => {
  // --- BACKEND MODE ---
  if (USE_BACKEND) {
    return api.deleteCall(id);
  }

  // --- LOCAL MODE ---
  const db = await initDB();
  const tx = db.transaction(STORE_NAME, 'readwrite');
  const store = tx.objectStore(STORE_NAME);
  store.delete(id);
  return new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
};

