require('dotenv').config();

const app = express();
const upload = multer({ dest: 'uploads/' });
const port = 3000;

// Setup Database (SQLite - Simple single file DB)
const db = new sqlite3.Database('./salesiq.db');

db.serialize(() => {
  // Create Calls Table
  db.run(`CREATE TABLE IF NOT EXISTS calls (
    id TEXT PRIMARY KEY,
    fileName TEXT,
    dateSaved INTEGER,
    summary TEXT,
    callScore INTEGER,
    data TEXT  -- We will store the full JSON analysis here for simplicity
  )`);

