  )`);
});

app.use(cors());
app.use(express.json());

// --- ROUTES ---

// 1. Analyze Call (Proxies request to Gemini to hide API Key)
app.post('/api/analyze/call', upload.single('audio'), async (req, res) => {
  if (!process.env.API_KEY) return res.status(500).json({ error: "Server missing API Key" });

  try {
    const audioPath = req.file.path;
    const audioBuffer = fs.readFileSync(audioPath);
    const base64Audio = audioBuffer.toString('base64');
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Use Gemini 2.5 Flash for speed
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
          { inlineData: { mimeType: req.file.mimetype || 'audio/mp3', data: base64Audio } },
          { text: "Analyze this sales call. Return valid JSON matching the schema..." } // (Full prompt same as frontend)
        ]
      },
      config: { responseMimeType: "application/json" }
    });

    // Cleanup uploaded file
    fs.unlinkSync(audioPath);

    // Parse and Return
    const json = JSON.parse(response.text());
    res.json(json);

  } catch (e) {
    console.error(e);
    res.status(500).json({ error: "Analysis failed", details: e.message });
  }
});

