  const { id, fileName, dateSaved, summary, stats, analysisData } = req.body;
  const stmt = db.prepare("INSERT OR REPLACE INTO calls VALUES (?, ?, ?, ?, ?, ?)");
  stmt.run(id, fileName, dateSaved, summary, stats.callScore, JSON.stringify(req.body));
  stmt.finalize();
  res.json({ success: true });
});

