        <Database className="w-4 h-4" />
        Sync to CRM
      </button>
    );
  }

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden border border-slate-200">
        <div className="flex justify-between items-center p-6 border-b border-slate-100 bg-slate-50">
          <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
            <Server className="w-5 h-5 text-indigo-600" />
            CRM Integration API
          </h3>
          <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-slate-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6">
          <p className="text-sm text-slate-600 mb-4">
            This action will push the analyzed call data, sentiment scores, and coaching insights to your connected CRM (Salesforce / HubSpot) via REST API.
          </p>

          <div className="bg-slate-900 rounded-lg p-4 font-mono text-xs text-green-400 overflow-y-auto max-h-[300px] mb-6 border border-slate-700">
            <pre>{JSON.stringify({
              object: "CallLog",
              action: "create",
              source: "SalesIQ_Coach",
              payload: {
                call_score: data?.callStats?.callScore ?? 0,
                sentiment_trend: "Positive", 
                risk_level: data?.dealIntelligence?.riskAnalysis?.riskLevel ?? 'Medium',
                compliance_score: data?.compliance?.complianceScore ?? 0,
                deal_stage_recommendation: data?.dealIntelligence?.dealStage?.recommendedStage ?? 'N/A',
                meeting_notes: data?.coachingCard?.overallSummary ?? '',
                next_steps: data?.coachingCard?.nextActions ?? [],
                deal_health_suggestions: data?.dealIntelligence?.riskAnalysis?.riskFactors ?? [],
                key_takeaways: data?.coachingCard?.keyTakeaways ?? [],
                sentiment_score: data?.callStats?.scoreBreakdown?.sentimentContribution ?? 0
              }
            }, null, 2)}</pre>
          </div>

          <div className="flex justify-end gap-3">
             <button 
               onClick={() => setIsOpen(false)}
               className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-100 rounded-lg"
             >
               Cancel
             </button>
             <button 
               onClick={handleSync}
               disabled={status !== 'IDLE'}
               className={`
                 flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold text-white transition-all
                 ${status === 'SUCCESS' ? 'bg-green-500' : 'bg-indigo-600 hover:bg-indigo-700'}
               `}
             >
               {status === 'SYNCING' && <Loader2 className="w-4 h-4 animate-spin" />}
               {status === 'SUCCESS' && <Check className="w-4 h-4" />}
               {status === 'IDLE' ? 'Push Data to CRM' : status === 'SYNCING' ? 'Syncing...' : 'Synced!'}
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

/**
 * SALESIQ SIMPLE BACKEND
 * Requirements: npm install express cors sqlite3 multer @google/genai dotenv
 */

const express = require('express');
const cors = require('cors');
const sqlite3 = require('sqlite3').verbose();
const multer = require('multer');
const fs = require('fs');
const { GoogleGenAI } = require("@google/genai");
require('dotenv').config();

const app = express();
const upload = multer({ dest: 'uploads/' });
const db = new sqlite3.Database('./sales_iq.db');

app.use(cors());
app.use(express.json());

// Initialize SQL Database
db.serialize(() => {
  db.run(`CREATE TABLE IF NOT EXISTS calls (
    id TEXT PRIMARY KEY,
    fileName TEXT,
    dateSaved INTEGER,
    summary TEXT,
    callScore INTEGER,
    data TEXT
  )`);
});

// GEMINI ANALYSIS ENDPOINT
app.post('/api/analyze/call', upload.single('audio'), async (req, res) => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API Key missing on server");

    const audioPath = req.file.path;
    const audioBuffer = fs.readFileSync(audioPath);
    const base64Audio = audioBuffer.toString('base64');

    const ai = new GoogleGenAI({ apiKey });
    // Using gemini-3-flash-preview for high performance/cost ratio
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Analyze this sales call. Output valid JSON matching the SalesAnalysisResult schema. Ensure objects like callStats and dealIntelligence are present.",
      config: { responseMimeType: "application/json" }
    });

    // Cleanup file
    fs.unlinkSync(audioPath);

    res.json(JSON.parse(response.text));
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: error.message });
  }
});

// SQL CRUD ENDPOINTS
app.get('/api/calls', (req, res) => {
  db.all("SELECT data FROM calls ORDER BY dateSaved DESC", (err, rows) => {
    if (err) return res.status(500).json(err);
    res.json(rows.map(r => JSON.parse(r.data)));
  });
});

app.post('/api/calls', (req, res) => {
  const call = req.body;
  const stmt = db.prepare("INSERT OR REPLACE INTO calls VALUES (?, ?, ?, ?, ?, ?)");
  // Defensive check for nested stats
  const score = (call.stats && typeof call.stats.callScore === 'number') ? call.stats.callScore : 0;
  stmt.run(call.id, call.fileName, call.dateSaved, call.summary, score, JSON.stringify(call));
  stmt.finalize();
  res.json({ success: true });
});

app.delete('/api/calls/:id', (req, res) => {
  db.run("DELETE FROM calls WHERE id = ?", req.params.id, (err) => {
    if (err) return res.status(500).json(err);
    res.json({ success: true });
  });
});

const PORT = 3000;
app.listen(PORT, () => console.log(`SalesIQ Backend ready on http://localhost:${PORT}`));

import React, { useState } from 'react';
import { ProspectProfile, FollowUpContent } from '../types';
import { UserCog, BrainCircuit, Mail, Copy, Check, Calendar, ChevronDown, ListChecks } from 'lucide-react';

interface CustomerProfileProps {
  profile?: ProspectProfile;
  followUp?: FollowUpContent;
}

export const CustomerProfile: React.FC<CustomerProfileProps> = ({ profile, followUp }) => {
  const [copied, setCopied] = useState(false);
  const [selectedTone, setSelectedTone] = useState<'Default' | 'Professional' | 'Friendly' | 'Urgent'>('Default');

  // Determine current email content based on selected tone
  const currentEmail = React.useMemo(() => {
    // Defensive check to prevent crash if followUp is missing
    const safeFollowUp = followUp || { 
      emailSubject: 'Follow-up', 
      emailBody: '', 
      agendaItems: [], 
      emailVariations: [], 
      proposalBullets: [] 
    };

    if (selectedTone === 'Default' || !safeFollowUp.emailVariations || safeFollowUp.emailVariations.length === 0) {
      return { subject: safeFollowUp.emailSubject, body: safeFollowUp.emailBody };
    }

    const variation = safeFollowUp.emailVariations.find(v => v.tone === selectedTone);
    return variation 
      ? { subject: variation.subject, body: variation.body } 
      : { subject: safeFollowUp.emailSubject, body: safeFollowUp.emailBody };
  }, [selectedTone, followUp]);

  const handleCopy = () => {
    const text = `Subject: ${currentEmail.subject}\n\n${currentEmail.body}`;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadICS = () => {
    const now = new Date();
    // Start tomorrow at 10 AM
    const start = new Date(now);
    start.setDate(start.getDate() + 1);
    start.setHours(10, 0, 0, 0);

    // End 1 hour later
    const end = new Date(start);
    end.setHours(11, 0, 0, 0);

    const formatDate = (date: Date) => date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';

    const icsContent = `BEGIN:VCALENDAR
VERSION:2.0
PRODID:-//SalesIQ//Coach//EN
BEGIN:VEVENT
UID:${Date.now()}@salesiq.app
DTSTAMP:${formatDate(new Date())}
DTSTART:${formatDate(start)}
DTEND:${formatDate(end)}
SUMMARY:Follow-up: ${currentEmail.subject}
DESCRIPTION:${(followUp?.agendaItems || []).map(i => `• ${i}`).join('\\n')}
END:VEVENT
END:VCALENDAR`;

    const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'follow_up.ics';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getDiscColor = (type?: string) => {
    switch (type) {
      case 'Dominance': return 'text-red-600 bg-red-50 border-red-200';
      case 'Influence': return 'text-yellow-600 bg-yellow-50 border-yellow-200';
      case 'Steadiness': return 'text-green-600 bg-green-50 border-green-200';
      case 'Conscientiousness': return 'text-blue-600 bg-blue-50 border-blue-200';
      default: return 'text-slate-600 bg-slate-50 border-slate-200';
    }
  };

  if (!profile && !followUp) return null;

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">

      {/* Prospect Personality */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col">
        <div className="flex items-center gap-2 mb-6">
          <BrainCircuit className="w-5 h-5 text-indigo-600" />
          <h3 className="font-bold text-slate-800">Prospect Personality (DiSC)</h3>
        </div>

        {profile ? (
          <>
            <div className="flex items-center gap-6 mb-6">
               {profile.avatarBase64 ? (
                  <div className="relative">
                     <img 
                        src={`data:image/png;base64,${profile.avatarBase64}`} 
                        alt="AI Generated Prospect Avatar" 
                        className={`w-24 h-24 rounded-full object-cover border-4 shadow-md ${getDiscColor(profile.discType)}`}
                     />
                     <div className="absolute -bottom-2 -right-2 bg-indigo-600 text-white text-[10px] font-bold px-2 py-1 rounded-full shadow-sm border-2 border-white">
                        AI GEN
                     </div>
                  </div>
               ) : (
                  <div className={`w-20 h-20 rounded-full flex items-center justify-center text-3xl font-bold border-2 shadow-sm ${getDiscColor(profile.discType)}`}>
                    {profile.discType?.charAt(0) || '?'}
                  </div>
               )}

               <div>
                 <h4 className="font-bold text-xl text-slate-800">{profile.discType || 'Unknown'}</h4>
                 <p className="text-sm text-slate-500 font-medium mb-1">{profile.communicationStyle}</p>
                 <span className={`text-[10px] uppercase font-bold px-2 py-0.5 rounded border ${getDiscColor(profile.discType)}`}>
                   Analyzed
                 </span>
               </div>
            </div>

            <div className="bg-slate-50 rounded-lg p-4 border border-slate-100 flex-grow">
              <h5 className="text-xs font-bold text-slate-500 uppercase mb-2 flex items-center gap-1">
                <UserCog className="w-3 h-3" /> Adaptation Strategy
              </h5>
              <ul className="space-y-2">
                {(profile.sellingTips || []).map((tip, idx) => (
                  <li key={idx} className="text-sm text-slate-700 flex gap-2 items-start">
                    <span className="text-indigo-500 font-bold">•</span>
                    {tip}
                  </li>
                ))}
              </ul>
            </div>
          </>
        ) : (
          <div className="flex-grow flex items-center justify-center text-slate-400 italic text-sm">
            Personality analysis unavailable for this call.
          </div>
        )}
      </div>

      {/* Smart Follow-Up */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <Mail className="w-5 h-5 text-blue-500" />
            <h3 className="font-bold text-slate-800">Smart Follow-Up</h3>
          </div>

          {followUp && (
            <div className="flex gap-2">
              {/* Tone Selector */}
              <div className="relative group">
                 <button className="flex items-center gap-1 text-xs font-medium text-slate-600 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-200 hover:border-blue-300 transition-colors">
                   {selectedTone === 'Default' ? 'Default Tone' : `${selectedTone} Tone`}
                   <ChevronDown className="w-3 h-3" />
                 </button>
                 <div className="absolute right-0 top-full mt-1 bg-white border border-slate-200 rounded-lg shadow-lg py-1 w-32 hidden group-hover:block z-20">
                   {['Default', 'Professional', 'Friendly', 'Urgent'].map(tone => (
                     <button 
                       key={tone}
